    $(".splitedText").keyup(function () {
        if (this.value.length == this.maxLength) {

            $otpArray[$(this).attr("tabindex")] = this.value;
            $(".prefcode_full_value").val('');
            $('.otpkeyEdit').val('');
            for (var i = 0; i < $otpArray.length; i++) {
                if ($otpArray[i] !== undefined) {
                    $(".prefcode_full_value").val($('.prefcode_full_value').val().length != 0 ? $(".prefcode_full_value").val() + $otpArray[i] : $otpArray[i]);
                    $(".otpkeyEdit").val($('.otpkeyEdit').val().length != 0 ? $(".otpkeyEdit").val() + $otpArray[i] : $otpArray[i]);
                }
            }
            if ($(".prefcode_full_value").val().length == 6) {
                $('.button2facheck').prop('disabled', false);
            }
            if ($(this).next('.splitedText').length) {
                $(this).next('.splitedText').focus();
                $(this).next('.splitedText')[0].setSelectionRange(0, 1);
            } else {
                $('.button2facheck').focus();
            }
        }
    });

    $('.splitedText').on('paste', function (e) {
        e.preventDefault();
        var paste = (e.originalEvent.clipboardData || window.clipboardData).getData('text');
        paste = paste.replace(/\D/g, '');

        if (!paste.length) return;

        $('.splitedText').each(function (i) {
            $(this).val(paste[i] !== undefined ? paste[i] : '');
        });

        $('.prefcode_full_value').val(paste.substring(0, 6));
        $('.otpkeyEdit').val(paste.substring(0, 6));

        if (paste.length >= 6) {
            $('.button2facheck').prop('disabled', false);
        }

        // NEW — ensure tab behaviour still works
        var inputs = $('.splitedText');
        var focused = false;

        inputs.each(function () {
            if (!focused && !$(this).val()) {
                $(this).focus();
                focused = true;
            }
        });

        if (!focused) {
            inputs.last().focus();
        }
    });

    // helper to rebuild the combined OTP value and enable/disable button
    function updateCombinedOtp() {
        var combined = '';
        $('.prefcode_otp').each(function () {
            var v = $(this).val();
            if (v !== undefined && v !== null && v !== '') combined += v;
        });
        $('.prefcode_full_value').val(combined);
        $('.otpkeyEdit').val(combined);
        $('.button2facheck').prop('disabled', combined.length !== 6);
    }

    // REPLACE your existing keydown/backspace handler with this:
    $('.prefcode_otp').off('keydown.prefcodeBackspace').on('keydown.prefcodeBackspace', function (e) {
        var key = e.key || e.keyCode;
        var $current = $(this);

        // Backspace
        if (key === 'Backspace' || key === 8) {
            // If current has a value, clear it and update state.
            if ($current.val() !== '') {
                // Prevent default so browser doesn't navigate back on empty inputs in some contexts
                e.preventDefault();
                $current.val('');
                updateCombinedOtp();
                // keep focus on current so repeated backspaces will clear it if user typed multiple chars somehow
                try {
                    $current[0].setSelectionRange(0, 1);
                } catch (err) {}
                return;
            }

            // current is empty -> go to previous tabindex and clear that
            // prevent default to avoid browser back navigation
            e.preventDefault();

            var tabindex = parseInt($current.attr('tabindex'), 10);
            if (isNaN(tabindex)) {
                // fallback to DOM previous if no tabindex present
                var $prevDom = $current.prevAll('.prefcode_otp').first();
                if ($prevDom.length) {
                    $prevDom.val('');
                    $prevDom.focus();
                    updateCombinedOtp();
                    try {
                        $prevDom[0].setSelectionRange(0, 1);
                    } catch (err) {}
                }
                return;
            }

            // find previous by tabindex (tabindex - 1, -2 ... until found)
            var prevIndex = tabindex - 1;
            while (prevIndex >= 0) {
                var $prev = $('.prefcode_otp[tabindex="' + prevIndex + '"]');
                if ($prev.length) {
                    $prev.val('');
                    $prev.focus();
                    updateCombinedOtp();
                    try {
                        $prev[0].setSelectionRange(0, 1);
                    } catch (err) {}
                    return;
                }
                prevIndex--;
            }

            // nothing to delete left of first -> do nothing
            return;
        }

        // Delete key - clear current and update
        if (key === 'Delete' || key === 46) {
            e.preventDefault();
            $current.val('');
            updateCombinedOtp();
            try {
                $current[0].setSelectionRange(0, 1);
            } catch (err) {}
            return;
        }
    });

